import{_ as t,o as a,c as o,a0 as i}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Where Did My Data Go?","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting/missing-data.md","filePath":"troubleshooting/missing-data.md"}'),s={name:"troubleshooting/missing-data.md"};function r(l,e,n,h,d,c){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="where-did-my-data-go" tabindex="-1">Where Did My Data Go? <a class="header-anchor" href="#where-did-my-data-go" aria-label="Permalink to &quot;Where Did My Data Go?&quot;">â€‹</a></h1><p>When data looks missing, use these four questions in order before assuming it was destroyed.</p><h2 id="_1-was-it-deleted" tabindex="-1">1. Was it deleted? <a class="header-anchor" href="#_1-was-it-deleted" aria-label="Permalink to &quot;1. Was it deleted?&quot;">â€‹</a></h2><p>Check the <a href="./../how-to/recycle-bin.html">Recycle Bin</a> first.</p><p>If the item is there:</p><ul><li>restore it directly if your role allows that</li><li>or use <a href="./../how-to/restore-requests.html">Request &amp; Approve Restores</a> if you need an approver</li></ul><p>Most deletes in the app are soft deletes, not permanent destruction. See <a href="./../reference/soft-delete.html">What &quot;Delete&quot; Really Does</a>.</p><h2 id="_2-am-i-in-the-wrong-context-or-scope" tabindex="-1">2. Am I in the wrong context or scope? <a class="header-anchor" href="#_2-am-i-in-the-wrong-context-or-scope" aria-label="Permalink to &quot;2. Am I in the wrong context or scope?&quot;">â€‹</a></h2><p>Look at the context banner and the current page scope before doing anything else.</p><p>Common causes:</p><ul><li>the wrong kingdom is selected</li><li>the wrong alliance is selected</li><li>you are using an old bookmark into a page outside your role&#39;s scope</li></ul><p>Use <a href="./../getting-started/navigating.html">Finding Your Way Around</a> and <a href="./../getting-started/access-denied.html">&quot;You don&#39;t have access&quot;</a>.</p><h2 id="_3-was-an-import-rolled-back" tabindex="-1">3. Was an import rolled back? <a class="header-anchor" href="#_3-was-an-import-rolled-back" aria-label="Permalink to &quot;3. Was an import rolled back?&quot;">â€‹</a></h2><p>If the missing data came from an import, check whether that import was deleted with results and moved to <code>rolled_back</code>.</p><p>If that happened:</p><ul><li>the written results may have been intentionally undone</li><li>the import can be restored as a reviewable draft through <a href="./../imports/restore-import.html">Restore a Deleted Import</a></li><li>if you still want those rows live again, review them and accept them again</li></ul><p>The safe rollback behavior is described in <a href="./../imports/delete-and-rollback.html">Delete an Import &amp; Roll Back Its Changes</a>.</p><h2 id="_4-is-the-session-locked" tabindex="-1">4. Is the session locked? <a class="header-anchor" href="#_4-is-the-session-locked" aria-label="Permalink to &quot;4. Is the session locked?&quot;">â€‹</a></h2><p>Sometimes the data is not gone. The page is simply locked against changes.</p><p>If the instance is locked:</p><ul><li>imports are blocked</li><li>edits are blocked</li><li>you need the unlock flow in <a href="./../how-to/session-lock.html">Locked Instances &amp; Unlock Requests</a></li></ul><h2 id="if-none-of-the-above-explains-it" tabindex="-1">If none of the above explains it <a class="header-anchor" href="#if-none-of-the-above-explains-it" aria-label="Permalink to &quot;If none of the above explains it&quot;">â€‹</a></h2><p>File a report so a senior role can investigate:</p><ul><li><a href="./../how-to/reports.html">File &amp; Track Reports</a></li></ul>',24)])])}const u=t(s,[["render",r]]);export{m as __pageData,u as default};
